import numpy as np
from scipy.linalg import expm
from typing import Dict, List

class PatternQBM:
    def __init__(self, n_visible: int, n_hidden: int, beta: float = 1.0):
        self.n_visible = n_visible
        self.n_hidden = n_hidden
        self.n_total = n_visible + n_hidden
        self.dim = 2 ** self.n_total
        self.beta = beta

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

        self.params = self._init_params()

    def _init_params(self) -> Dict[str, np.ndarray]:
        return {
            'a': np.random.randn(self.n_visible) * 0.1,
            'b': np.random.randn(self.n_hidden) * 0.1,
            'W': np.random.randn(self.n_visible, self.n_hidden) * 0.1,
            'gamma': 0.1
        }

    def _single_op(self, op: np.ndarray, qubit: int) -> np.ndarray:
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_total):
            result = np.kron(result, op if i == qubit else self.I)
        return result

    def build_hamiltonian(self) -> np.ndarray:
        H = np.zeros((self.dim, self.dim), dtype=complex)

        for i in range(self.n_visible):
            H -= self.params['a'][i] * self._single_op(self.Z, i)

        for j in range(self.n_hidden):
            H -= self.params['b'][j] * self._single_op(self.Z, self.n_visible + j)

        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
                H -= self.params['W'][i, j] * ZZ

        for k in range(self.n_total):
            H -= self.params['gamma'] * self._single_op(self.X, k)

        return H

    def visible_probabilities(self) -> np.ndarray:
        H = self.build_hamiltonian()
        exp_H = expm(-self.beta * H)
        rho = exp_H / np.trace(exp_H)

        dim_v = 2 ** self.n_visible
        dim_h = 2 ** self.n_hidden

        rho_reshaped = rho.reshape(dim_v, dim_h, dim_v, dim_h)
        rho_v = np.einsum('ijik->jk', rho_reshaped)

        return np.real(np.diag(rho_v))

    def generate(self, n_samples: int) -> np.ndarray:
        probs = self.visible_probabilities()
        probs = probs / np.sum(probs)

        indices = np.random.choice(len(probs), size=n_samples, p=probs)

        return np.array([[(idx >> i) & 1 for i in range(self.n_visible)] for idx in indices])

    def train(self, patterns: np.ndarray, n_epochs: int = 100, lr: float = 0.1):
        for epoch in range(n_epochs):
            H = self.build_hamiltonian()
            exp_H = expm(-self.beta * H)
            rho = exp_H / np.trace(exp_H)

            grad_a = np.zeros(self.n_visible)
            grad_b = np.zeros(self.n_hidden)
            grad_W = np.zeros((self.n_visible, self.n_hidden))

            for i in range(self.n_visible):
                grad_a[i] = -self.beta * np.real(np.trace(self._single_op(self.Z, i) @ rho))

            for j in range(self.n_hidden):
                grad_b[j] = -self.beta * np.real(np.trace(self._single_op(self.Z, self.n_visible + j) @ rho))

            for i in range(self.n_visible):
                for j in range(self.n_hidden):
                    ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
                    grad_W[i, j] = -self.beta * np.real(np.trace(ZZ @ rho))

            for v in patterns:
                for i in range(self.n_visible):
                    grad_a[i] += self.beta * (1 - 2 * v[i]) / len(patterns)

            self.params['a'] -= lr * grad_a
            self.params['b'] -= lr * grad_b
            self.params['W'] -= lr * grad_W

            if epoch % 20 == 0:
                ll = self.compute_log_likelihood(patterns)
                print(f"Epoch {epoch}: LL = {ll:.4f}")

    def compute_log_likelihood(self, patterns: np.ndarray) -> float:
        probs = self.visible_probabilities()
        ll = 0.0
        for v in patterns:
            idx = int(sum(v[i] * 2**i for i in range(self.n_visible)))
            ll += np.log(max(probs[idx], 1e-10))
        return ll / len(patterns)

import numpy as np
from scipy.linalg import expm
from typing import Tuple

class MaxCutQBM:
    def __init__(self, n_nodes: int, beta: float = 5.0, gamma: float = 0.3):
        self.n_nodes = n_nodes
        self.dim = 2 ** n_nodes
        self.beta = beta
        self.gamma = gamma

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

    def _single_op(self, op: np.ndarray, qubit: int) -> np.ndarray:
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_nodes):
            result = np.kron(result, op if i == qubit else self.I)
        return result

    def encode_maxcut(self, adjacency: np.ndarray) -> np.ndarray:
        H = np.zeros((self.dim, self.dim), dtype=complex)

        for i in range(self.n_nodes):
            for j in range(i + 1, self.n_nodes):
                if adjacency[i, j] != 0:
                    ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, j)
                    H += adjacency[i, j] / 2 * ZZ

        for k in range(self.n_nodes):
            H -= self.gamma * self._single_op(self.X, k)

        return H

    def compute_cut_value(self, x: np.ndarray, adjacency: np.ndarray) -> float:
        cut = 0.0
        for i in range(self.n_nodes):
            for j in range(i + 1, self.n_nodes):
                if x[i] != x[j]:
                    cut += adjacency[i, j]
        return cut

    def solve(self, adjacency: np.ndarray, n_samples: int = 100) -> Tuple[np.ndarray, float]:
        H = self.encode_maxcut(adjacency)

        exp_H = expm(-self.beta * H)
        rho = exp_H / np.trace(exp_H)

        probs = np.real(np.diag(rho))
        probs = np.clip(probs, 0, None)
        probs = probs / np.sum(probs)

        indices = np.random.choice(self.dim, size=n_samples, p=probs)

        best_cut = -1
        best_x = None

        for idx in indices:
            x = np.array([(idx >> i) & 1 for i in range(self.n_nodes)])
            cut = self.compute_cut_value(x, adjacency)
            if cut > best_cut:
                best_cut = cut
                best_x = x

        return best_x, best_cut

    def solve_with_annealing(self, adjacency: np.ndarray, n_steps: int = 50) -> Tuple[np.ndarray, float]:
        H0 = np.zeros((self.dim, self.dim), dtype=complex)
        for k in range(self.n_nodes):
            H0 -= self._single_op(self.X, k)

        H_problem = np.zeros((self.dim, self.dim), dtype=complex)
        for i in range(self.n_nodes):
            for j in range(i + 1, self.n_nodes):
                if adjacency[i, j] != 0:
                    ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, j)
                    H_problem += adjacency[i, j] / 2 * ZZ

        psi = np.ones(self.dim, dtype=complex) / np.sqrt(self.dim)
        dt = 0.1

        for step in range(n_steps):
            s = step / n_steps
            H_t = (1 - s) * H0 + s * H_problem
            U = expm(-1j * dt * H_t)
            psi = U @ psi

        probs = np.abs(psi) ** 2

        best_cut = -1
        best_x = None

        for idx in range(self.dim):
            if probs[idx] > 0.01:
                x = np.array([(idx >> i) & 1 for i in range(self.n_nodes)])
                cut = self.compute_cut_value(x, adjacency)
                if cut > best_cut:
                    best_cut = cut
                    best_x = x

        return best_x, best_cut

import numpy as np
from scipy.linalg import expm
from typing import Dict, Tuple

class QBMBinaryClassifier:
    def __init__(self, n_features: int, n_hidden: int, beta: float = 1.0):
        self.n_features = n_features
        self.n_hidden = n_hidden
        self.n_visible = n_features + 1
        self.n_total = self.n_visible + n_hidden
        self.dim = 2 ** self.n_total
        self.beta = beta

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

        self.params = self._init_params()

    def _init_params(self) -> Dict[str, np.ndarray]:
        return {
            'a': np.random.randn(self.n_visible) * 0.1,
            'b': np.random.randn(self.n_hidden) * 0.1,
            'W': np.random.randn(self.n_visible, self.n_hidden) * 0.1,
            'gamma': 0.1
        }

    def _single_op(self, op: np.ndarray, qubit: int) -> np.ndarray:
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_total):
            result = np.kron(result, op if i == qubit else self.I)
        return result

    def build_hamiltonian(self) -> np.ndarray:
        H = np.zeros((self.dim, self.dim), dtype=complex)

        for i in range(self.n_visible):
            H -= self.params['a'][i] * self._single_op(self.Z, i)

        for j in range(self.n_hidden):
            H -= self.params['b'][j] * self._single_op(self.Z, self.n_visible + j)

        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
                H -= self.params['W'][i, j] * ZZ

        for k in range(self.n_total):
            H -= self.params['gamma'] * self._single_op(self.X, k)

        return H

    def _create_projector(self, observed: Dict[int, int]) -> np.ndarray:
        proj = np.eye(self.dim, dtype=complex)
        for qubit, value in observed.items():
            P_single = np.zeros((2, 2), dtype=complex)
            P_single[value, value] = 1.0

            P_full = np.array([[1]], dtype=complex)
            for i in range(self.n_total):
                if i == qubit:
                    P_full = np.kron(P_full, P_single)
                else:
                    P_full = np.kron(P_full, self.I)
            proj = proj @ P_full
        return proj

    def predict_proba(self, x: np.ndarray) -> float:
        H = self.build_hamiltonian()
        exp_H = expm(-self.beta * H)
        rho = exp_H / np.trace(exp_H)

        observed_0 = {i: int(x[i]) for i in range(self.n_features)}
        observed_0[self.n_features] = 0

        observed_1 = {i: int(x[i]) for i in range(self.n_features)}
        observed_1[self.n_features] = 1

        proj_0 = self._create_projector(observed_0)
        proj_1 = self._create_projector(observed_1)

        p_0 = np.real(np.trace(proj_0 @ rho @ proj_0))
        p_1 = np.real(np.trace(proj_1 @ rho @ proj_1))

        return p_1 / (p_0 + p_1 + 1e-10)

    def predict(self, x: np.ndarray) -> int:
        return 1 if self.predict_proba(x) > 0.5 else 0

    def train(self, X: np.ndarray, y: np.ndarray, n_epochs: int = 50, lr: float = 0.1):
        for epoch in range(n_epochs):
            total_loss = 0.0
            eps = 1e-4

            for x, label in zip(X, y):
                base_prob = self.predict_proba(x)
                if label == 1:
                    total_loss -= np.log(max(base_prob, 1e-10))
                else:
                    total_loss -= np.log(max(1 - base_prob, 1e-10))

                for i in range(self.n_visible):
                    self.params['a'][i] += eps
                    new_prob = self.predict_proba(x)
                    if label == 1:
                        grad = -(new_prob - base_prob) / eps
                    else:
                        grad = (new_prob - base_prob) / eps
                    self.params['a'][i] -= eps + lr * grad

            if epoch % 10 == 0:
                print(f"Epoch {epoch}: Loss = {total_loss / len(X):.4f}")

    def evaluate(self, X: np.ndarray, y: np.ndarray) -> float:
        correct = sum(self.predict(x) == label for x, label in zip(X, y))
        return correct / len(X)

import numpy as np
from scipy.linalg import expm
from typing import Dict, List, Tuple

class QBMBenchmarkSuite:
    def __init__(self, n_visible: int, n_hidden: int):
        self.n_visible = n_visible
        self.n_hidden = n_hidden
        self.n_total = n_visible + n_hidden
        self.dim = 2 ** self.n_total
        self.beta = 1.0

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

    def generate_bars_data(self, n_samples: int) -> np.ndarray:
        side = int(np.sqrt(self.n_visible))
        data = []
        for _ in range(n_samples):
            img = np.zeros((side, side))
            if np.random.random() > 0.5:
                row = np.random.randint(side)
                img[row, :] = 1
            else:
                col = np.random.randint(side)
                img[:, col] = 1
            data.append(img.flatten())
        return np.array(data)

    def generate_corners_data(self, n_samples: int) -> np.ndarray:
        side = int(np.sqrt(self.n_visible))
        corners = [(0, 0), (0, side-2), (side-2, 0), (side-2, side-2)]
        data = []
        for _ in range(n_samples):
            img = np.zeros((side, side))
            r, c = corners[np.random.randint(4)]
            img[r:min(r+2, side), c:min(c+2, side)] = 1
            data.append(img.flatten())
        return np.array(data)

    def _single_op(self, op, qubit):
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_total):
            result = np.kron(result, op if i == qubit else self.I)
        return result

    def _build_hamiltonian(self, params: Dict[str, np.ndarray]) -> np.ndarray:
        H = np.zeros((self.dim, self.dim), dtype=complex)
        for i in range(self.n_visible):
            H -= params['a'][i] * self._single_op(self.Z, i)
        for j in range(self.n_hidden):
            H -= params['b'][j] * self._single_op(self.Z, self.n_visible + j)
        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
                H -= params['W'][i, j] * ZZ
        for k in range(self.n_total):
            H -= params['gamma'] * self._single_op(self.X, k)
        return H

    def _visible_probs(self, params: Dict[str, np.ndarray]) -> np.ndarray:
        H = self._build_hamiltonian(params)
        exp_H = expm(-self.beta * H)
        rho = exp_H / np.trace(exp_H)
        dim_v = 2 ** self.n_visible
        dim_h = 2 ** self.n_hidden
        rho_reshaped = rho.reshape(dim_v, dim_h, dim_v, dim_h)
        rho_v = np.einsum('ijik->jk', rho_reshaped)
        return np.real(np.diag(rho_v))

    def train_classical_rbm(self, data: np.ndarray, n_epochs: int = 50) -> Dict[str, np.ndarray]:
        params = {
            'a': np.random.randn(self.n_visible) * 0.1,
            'b': np.random.randn(self.n_hidden) * 0.1,
            'W': np.random.randn(self.n_visible, self.n_hidden) * 0.1,
            'gamma': 0.0
        }
        lr = 0.1
        for _ in range(n_epochs):
            H = self._build_hamiltonian(params)
            exp_H = expm(-self.beta * H)
            rho = exp_H / np.trace(exp_H)
            grad_a = np.zeros(self.n_visible)
            for i in range(self.n_visible):
                grad_a[i] = -self.beta * np.real(np.trace(self._single_op(self.Z, i) @ rho))
            for v in data:
                for i in range(self.n_visible):
                    grad_a[i] += self.beta * (1 - 2 * v[i]) / len(data)
            params['a'] -= lr * grad_a
        return params

    def train_quantum_rbm(self, data: np.ndarray, gamma: float = 0.3, n_epochs: int = 50) -> Dict[str, np.ndarray]:
        params = {
            'a': np.random.randn(self.n_visible) * 0.1,
            'b': np.random.randn(self.n_hidden) * 0.1,
            'W': np.random.randn(self.n_visible, self.n_hidden) * 0.1,
            'gamma': gamma
        }
        lr = 0.1
        for _ in range(n_epochs):
            H = self._build_hamiltonian(params)
            exp_H = expm(-self.beta * H)
            rho = exp_H / np.trace(exp_H)
            grad_a = np.zeros(self.n_visible)
            for i in range(self.n_visible):
                grad_a[i] = -self.beta * np.real(np.trace(self._single_op(self.Z, i) @ rho))
            for v in data:
                for i in range(self.n_visible):
                    grad_a[i] += self.beta * (1 - 2 * v[i]) / len(data)
            params['a'] -= lr * grad_a
        return params

    def compute_log_likelihood(self, params: Dict[str, np.ndarray], data: np.ndarray) -> float:
        probs = self._visible_probs(params)
        ll = 0.0
        for v in data:
            idx = int(sum(v[i] * 2**i for i in range(self.n_visible)))
            ll += np.log(max(probs[idx], 1e-10))
        return ll / len(data)

    def compute_mode_coverage(self, params: Dict[str, np.ndarray], data: np.ndarray, n_samples: int = 500) -> float:
        probs = self._visible_probs(params)
        probs = probs / np.sum(probs)
        indices = np.random.choice(len(probs), size=n_samples, p=probs)
        samples = set(indices)
        data_modes = set(int(sum(v[i] * 2**i for i in range(self.n_visible))) for v in data)
        covered = len(samples & data_modes)
        return covered / len(data_modes)

    def run_benchmark(self, dataset: str = 'bars', n_trials: int = 5) -> Dict[str, Dict[str, float]]:
        if dataset == 'bars':
            data = self.generate_bars_data(100)
        else:
            data = self.generate_corners_data(100)

        results = {'classical': {'ll': [], 'coverage': []}, 'quantum': {'ll': [], 'coverage': []}}

        for _ in range(n_trials):
            c_params = self.train_classical_rbm(data)
            results['classical']['ll'].append(self.compute_log_likelihood(c_params, data))
            results['classical']['coverage'].append(self.compute_mode_coverage(c_params, data))

            q_params = self.train_quantum_rbm(data)
            results['quantum']['ll'].append(self.compute_log_likelihood(q_params, data))
            results['quantum']['coverage'].append(self.compute_mode_coverage(q_params, data))

        return {
            'classical': {k: np.mean(v) for k, v in results['classical'].items()},
            'quantum': {k: np.mean(v) for k, v in results['quantum'].items()}
        }
